import java.util.Map;
import java.util.Optional;

@Repository
public class ElasticsearchRepository {

    public static final String PRODUCT_INDEX = "products";
    public static final String SEARCH_QUERY_INDEX = "search_queries";

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    public ElasticsearchRepository(RestHighLevelClient client, ObjectMapper objectMapper) {
        this.client = client;
        this.objectMapper = objectMapper;
    }

    public void createIndicesIfNotExist() throws IOException {
        if (!client.indices().exists(new GetIndexRequest(PRODUCT_INDEX), RequestOptions.DEFAULT)) {
            CreateIndexRequest request = new CreateIndexRequest(PRODUCT_INDEX);
            request.settings(Settings.builder()
                    .put("index.number_of_shards", 1)
                    .put("index.number_of_replicas", 0));
            request.mapping(buildProductMapping(), XContentType.JSON);
            client.indices().create(request, RequestOptions.DEFAULT);
        }

        if (!client.indices().exists(new GetIndexRequest(SEARCH_QUERY_INDEX), RequestOptions.DEFAULT)) {
            CreateIndexRequest request = new CreateIndexRequest(SEARCH_QUERY_INDEX);
            request.settings(Settings.builder()
                    .put("index.number_of_shards", 1)
                    .put("index.number_of_replicas", 0));
            request.mapping(buildSearchQueryMapping(), XContentType.JSON);
            client.indices().create(request, RequestOptions.DEFAULT);
        }
    }

    public Product saveProduct(Product product) throws IOException {
        IndexRequest request = new IndexRequest(PRODUCT_INDEX)
                .id(product.getId())
                .source(objectMapper.writeValueAsString(product), XContentType.JSON)
                .setRefreshPolicy(WriteRequest.RefreshPolicy.IMMEDIATE);
        IndexResponse response = client.index(request, RequestOptions.DEFAULT);
        if (response.getResult() == DocWriteResponse.Result.CREATED || response.getResult() == DocWriteResponse.Result.UPDATED) {
            return product;
        }
        return null;
    }

    public void saveSearchQuery(SearchQuery query) throws IOException {
        IndexRequest request = new IndexRequest(SEARCH_QUERY_INDEX)
                .id(query.getId())
                .source(objectMapper.writeValueAsString(query), XContentType.JSON)
                .setRefreshPolicy(WriteRequest.RefreshPolicy.IMMEDIATE);
        client.index(request, RequestOptions.DEFAULT);
    }

    private String buildProductMapping() {
        return "{\n" +
                "  \"properties\": {\n" +
                "    \"id\": {\"type\": \"keyword\"},\n" +
                "    \"name\": {\"type\": \"text\", \"analyzer\": \"standard\"},\n" +
                "    \"description\": {\"type\": \"text\", \"analyzer\": \"standard\"},\n" +
                "    \"brand\": {\"type\": \"keyword\"},\n" +
                "    \"category\": {\"type\": \"keyword\"},\n" +
                "    \"tags\": {\"type\": \"keyword\"},\n" +
                "    \"price\": {\"type\": \"double\"},\n" +
                "    \"currency\": {\"type\": \"keyword\"},\n" +
                "    \"stock\": {\"type\": \"integer\"},\n" +
                "    \"rating\": {\"type\": \"double\"},\n" +
                "    \"createdAt\": {\"type\": \"date\"},\n" +
                "    \"updatedAt\": {\"type\": \"date\"}\n" +
                "  }\n" +
                "}";
    }

    private String buildSearchQueryMapping() {
        return "{\n" +
                "  \"properties\": {\n" +
                "    \"id\": {\"type\": \"keyword\"},\n" +
                "    \"userId\": {\"type\": \"keyword\"},\n" +
                "    \"query\": {\"type\": \"text\"},\n" +
                "    \"category\": {\"type\": \"keyword\"},\n" +
                "    \"brand\": {\"type\": \"keyword\"},\n" +
                "    \"minPrice\": {\"type\": \"double\"},\n" +
                "    \"maxPrice\": {\"type\": \"double\"},\n" +
                "    \"searchedAt\": {\"type\": \"date\"}\n" +
                "  }\n" +
                "}";
    }
}

package com.example.ecomsearch.service;

import com.example.ecomsearch.dto.ProductRequest;
import com.example.ecomsearch.dto.ProductResult;
import com.example.ecomsearch.dto.SearchRequest;
import com.example.ecomsearch.dto.SearchResponse;
import com.example.ecomsearch.model.Product;
import com.example.ecomsearch.model.SearchQuery;
import com.example.ecomsearch.repository.ElasticsearchRepository;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.search.SearchResponseSections;
import org.elasticsearch.action.search.SearchType;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.fetch.subphase.FetchSourceContext;
import org.elasticsearch.search.sort.SortOrder;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.Instant;
import java.util.*;
import java.util.stream.Collectors;

@Service
public class ProductSearchService {

    private final ElasticsearchRepository repository;
    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    public ProductSearchService(ElasticsearchRepository repository, RestHighLevelClient client, ObjectMapper objectMapper) {
        this.repository = repository;
        this.client = client;
        this.objectMapper = objectMapper;
    }

    public Product indexProduct(ProductRequest request) throws IOException {
        Product product = new Product(
                UUID.randomUUID().toString(),
                request.getName(),
                request.getDescription(),
                request.getBrand(),
                request.getCategory(),
                request.getTags(),
                request.getPrice(),
                request.getCurrency(),
                request.getStock(),
                request.getRating(),
                Instant.now(),
                Instant.now()
        );
        repository.saveProduct(product);
        return product;
    }

    public SearchResponse searchProducts(SearchRequest request, String userId) throws IOException {
        SearchQuery query = new SearchQuery(
                UUID.randomUUID().toString(),
                userId,
                request.getQuery(),
                request.getCategory(),
                request.getBrand(),
                request.getMinPrice(),
                request.getMaxPrice(),
                Instant.now()
        );
        repository.saveSearchQuery(query);

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        if (request.getQuery() != null && !request.getQuery().isBlank()) {
            boolQuery.must(QueryBuilders.multiMatchQuery(request.getQuery(), "name^3", "description", "brand^2", "category", "tags^2"));
        } else {
            boolQuery.must(QueryBuilders.matchAllQuery());
        }

        if (request.getCategory() != null && !request.getCategory().isBlank()) {
            boolQuery.filter(QueryBuilders.termQuery("category", request.getCategory()));
        }

        if (request.getBrand() != null && !request.getBrand().isBlank()) {
            boolQuery.filter(QueryBuilders.termQuery("brand", request.getBrand()));
        }

        if (request.getMinPrice() != null || request.getMaxPrice() != null) {
            if (request.getMinPrice() != null && request.getMaxPrice() != null) {
                boolQuery.filter(QueryBuilders.rangeQuery("price").gte(request.getMinPrice()).lte(request.getMaxPrice()));
            } else if (request.getMinPrice() != null) {
                boolQuery.filter(QueryBuilders.rangeQuery("price").gte(request.getMinPrice()));
            } else {
                boolQuery.filter(QueryBuilders.rangeQuery("price").lte(request.getMaxPrice()));
            }
        }

        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder()
                .query(boolQuery)
                .from(Math.max(0, request.getPage()) * Math.max(1, request.getSize()))
                .size(Math.max(1, request.getSize()))
                .fetchSource(new FetchSourceContext(true, new String[]{"id", "name", "description", "brand", "category", "tags", "price", "currency", "stock", "rating"}, new String[]{}))
                .aggregation(AggregationBuilders.terms("brands").field("brand").size(20))
                .aggregation(AggregationBuilders.terms("categories").field("category").size(20))
                .aggregation(AggregationBuilders.terms("tags").field("tags").size(20))
                .sort("_score", SortOrder.DESC)
                .sort("rating", SortOrder.DESC);

        org.elasticsearch.action.search.SearchRequest searchRequest = new org.elasticsearch.action.search.SearchRequest(ElasticsearchRepository.PRODUCT_INDEX);
        searchRequest.source(sourceBuilder);

        org.elasticsearch.action.search.SearchResponse response = client.search(searchRequest, RequestOptions.DEFAULT);

        List<ProductResult> products = Arrays.stream(response.getHits().getHits())
                .map(hit -> {
                    try {
                        Map<String, Object> source = hit.getSourceAsMap();
                        ProductResult result = new ProductResult();
                        result.setId((String) source.get("id"));
                        result.setName((String) source.get("name"));
                        result.setDescription((String) source.get("description"));
                        result.setBrand((String) source.get("brand"));
                        result.setCategory((String) source.get("category"));
                        result.setTags((List<String>) source.getOrDefault("tags", Collections.emptyList()));
                        Object price = source.get("price");
                        if (price != null) {
                            result.setPrice(new java.math.BigDecimal(price.toString()));
                        }
                        result.setCurrency((String) source.get("currency"));
                        Object stock = source.get("stock");
                        if (stock != null) {
                            result.setStock(Integer.valueOf(stock.toString()));
                        }
                        Object rating = source.get("rating");
                        if (rating != null) {
                            result.setRating(Double.valueOf(rating.toString()));
                        }
                        result.setScore(hit.getScore());
                        return result;
                    } catch (Exception e) {
                        throw new RuntimeException(e);
                    }
                })
                .collect(Collectors.toList());

        Map<String, Map<String, Long>> facets = new HashMap<>();
        facets.put("brands", extractTerms(response, "brands"));
        facets.put("categories", extractTerms(response, "categories"));
        facets.put("tags", extractTerms(response, "tags"));

        return new SearchResponse(products, facets, response.getHits().getTotalHits() != null ? response.getHits().getTotalHits().value : products.size());
    }

    private Map<String, Long> extractTerms(org.elasticsearch.action.search.SearchResponse response, String aggName) {
        Terms terms = response.getAggregations().get(aggName);
        Map<String, Long> result = new LinkedHashMap<>();
        if (terms != null) {
            for (Terms.Bucket bucket : terms.getBuckets()) {
                result.put(bucket.getKeyAsString(), bucket.getDocCount());
            }
        }
        return result;
    }
}

package com.example.ecomsearch.controller;

import com.example.ecomsearch.dto.ProductRequest;
import com.example.ecomsearch.dto.SearchRequest;
import com.example.ecomsearch.dto.SearchResponse;
import com.example.ecomsearch.model.Product;
import com.example.ecomsearch.service.ProductSearchService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;

@RestController
@RequestMapping("/api")
public class ProductController {

    private final ProductSearchService service;

    public ProductController(ProductSearchService service) {
        this.service = service;
    }

    @PostMapping("/products")
    public ResponseEntity<Product> indexProduct(@RequestBody ProductRequest request) throws IOException {
        return ResponseEntity.ok(service.indexProduct(request));
    }

    @PostMapping("/search")
    public ResponseEntity<SearchResponse> search(@RequestBody SearchRequest request, @RequestHeader(value = "X-User-Id", required = false) String userId) throws IOException {
        return ResponseEntity.ok(service.searchProducts(request, userId == null ? "anonymous" : userId));
    }
}

package com.example.ecomsearch.runner;

import com.example.ecomsearch.repository.ElasticsearchRepository;
import org.springframework.boot.CommandLineRunner;
import org.springframework.stereotype.Component;

@Component
public class IndexInitializer implements CommandLineRunner {

    private final ElasticsearchRepository repository;

    public IndexInitializer(ElasticsearchRepository repository) {
        this.repository = repository;
    }

    @Override
    public void run(String... args) throws Exception {
        repository.createIndicesIfNotExist();
    }
}

package com.example.ecomsearch.exception;

import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;

import java.io.IOException;
import java.util.HashMap;
import java.util.Map;

@RestControllerAdvice
public class GlobalExceptionHandler {

    @ExceptionHandler(IOException.class)
    public ResponseEntity<Map<String, Object>> handleIOException(IOException ex) {
        Map<String, Object> body = new HashMap<>();
        body.put("error", "Elasticsearch operation failed");
        body.put("message", ex.getMessage());
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(body);
    }

    @ExceptionHandler(Exception.class)
    public ResponseEntity<Map<String, Object>> handleException(Exception ex) {
        Map<String, Object> body = new HashMap<>();
        body.put("error", "Unexpected error");
        body.put("message", ex.getMessage());
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(body);
    }
}

package com.example.ecomsearch.util;

import java.util.UUID;

public final class IdUtil {
    private IdUtil() {
    }

    public static String randomId() {
        return UUID.randomUUID().toString();
    }
}